using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Opções" do Menu de Pausa (Tarefa #12) — "mais simples e funcional":
/// volume geral/música/efeitos, voz de Gaia (Dublado/OFF), velocidade e
/// tamanho do texto, vibração, mudar controles, idioma (só Português por
/// agora), Salvar, Carregar e Regressar ao título.
///
/// "Regressar ao Coração de Gaia" fica fora da lista principal, num pequeno
/// sub-menu "Sistema" (<see cref="systemMenu"/>) acessível por um botão
/// discreto no fundo da página — propositadamente longe de "Retomar" para não
/// ser escolhido por acidente. Confirma-se com <see cref="HoldToConfirmButton"/>
/// (segurar ~1s).
///
/// "Mudar controles" abre o sub-painel <see cref="rebindSection"/>
/// (<see cref="ControlsRebindSectionUI"/>). Ambos os sub-painéis escondem
/// <see cref="mainContentRoot"/> enquanto abertos e fecham com "B"/Escape via
/// ICancelHandler, devolvendo a selecção à página principal — cumprindo "o
/// menu precisa funcionar perfeitamente por comando e teclado, com selecção
/// inicial correcta e navegação clara".
///
/// Montagem no Editor:
/// - "firstSelectable": primeiro controlo a seleccionar ao abrir Opções
///   (ex: o slider de volume geral).
/// - "mainContentRoot": GameObject com todos os controlos normais (sliders,
///   toggles, botões) — escondido enquanto um sub-painel está aberto.
/// - "rebindSection"/"systemMenu": sub-painéis (próprios GameObjects,
///   inicialmente inactivos).
/// - "titleSceneName"/"heartOfGaiaSceneName": nomes das cenas para "Regressar
///   ao título" e "Regressar ao Coração de Gaia" (SceneManager.LoadSceneAsync).
/// </summary>
public class OptionsSectionUI : MonoBehaviour, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Tooltip("Conteúdo normal de Opções — escondido enquanto 'Mudar controles' ou 'Sistema' estão abertos.")]
    [SerializeField] private GameObject mainContentRoot;

    [Tooltip("Primeiro controlo a seleccionar ao abrir esta secção (selecção inicial correcta).")]
    [SerializeField] private Selectable firstSelectable;

    [Header("Som e Volumes")]
    [Tooltip("Volume geral.")]
    [SerializeField] private Slider masterVolumeSlider;
    [Tooltip("Música.")]
    [SerializeField] private Slider musicVolumeSlider;
    [Tooltip("Som de ambiente (BGS) — volume separado (Tarefa #38).")]
    [SerializeField] private Slider bgsVolumeSlider;
    [Tooltip("Efeitos.")]
    [SerializeField] private Slider sfxVolumeSlider;

    [Header("Voz de Gaia")]
    [Tooltip("\"Voz de Gaia - Dublado - OFF\".")]
    [SerializeField] private Toggle gaiaVoiceToggle;
    [SerializeField] private TMP_Text gaiaVoiceValueText;
    [SerializeField] private string gaiaVoiceOnText = "Dublado";
    [SerializeField] private string gaiaVoiceOffText = "OFF";

    [Header("Texto")]
    [SerializeField] private Slider textSpeedSlider;
    [SerializeField] private Button textSizeButton;
    [SerializeField] private TMP_Text textSizeValueText;
    [SerializeField] private string textSizePequenoText = "Pequeno";
    [SerializeField] private string textSizeMedioText = "Médio";
    [SerializeField] private string textSizeGrandeText = "Grande";

    [Header("Vibração")]
    [SerializeField] private Toggle vibrationToggle;

    [Header("Acessibilidade (Tarefa #40)")]
    [Tooltip("Desligar para remover o screen shake.")]
    [SerializeField] private Toggle screenShakeToggle;
    [Tooltip("Ligar para substituir flashes intensos por versões mais suaves.")]
    [SerializeField] private Toggle reducedFlashesToggle;

    [Header("Auras Pós-game (aparecem APENAS após obter o emblema correspondente)")]
    [Tooltip("Row completo (Label + Toggle) da Aura de Apolo — activar/desactivar conforme o EmblemManager.")]
    [SerializeField] private GameObject apoloAuraRow;
    [SerializeField] private Toggle apoloAuraToggle;

    [Tooltip("Row completo (Label + Toggle) da Aura de Gaia.")]
    [SerializeField] private GameObject gaiaAuraRow;
    [SerializeField] private Toggle gaiaAuraToggle;

    [Tooltip("Row completo (Label + Toggle) da Aura de Zeus.")]
    [SerializeField] private GameObject zeusAuraRow;
    [SerializeField] private Toggle zeusAuraToggle;

    [Tooltip("EmblemData do Emblema de Apolo — usado para verificar se o Emblema foi obtido (via obtainedVariable em GameVariables).")]
    [SerializeField] private EmblemData apoloEmblemData;
    [Tooltip("EmblemData do Emblema de Gaia.")]
    [SerializeField] private EmblemData gaiaEmblemData;
    [Tooltip("EmblemData do Emblema de Zeus.")]
    [SerializeField] private EmblemData zeusEmblemData;

    [Header("Mudar Controles")]
    [SerializeField] private Button changeControlsButton;
    [SerializeField] private ControlsRebindSectionUI rebindSection;

    [Header("Idioma")]
    [Tooltip("Botão ciclável — muda para o próximo idioma disponível (GameSettings.CycleLanguage). Por agora só Português está disponível; os botões de idiomas futuros não terão efeito até serem marcados como available em GameSettings.IsLanguageAvailable.")]
    [SerializeField] private Button languageButton;
    [Tooltip("Texto que mostra o idioma activo (ex: \"Português\"). Actualizado automaticamente por RefreshLanguageText().")]
    [SerializeField] private TMP_Text languageValueText;

    [Header("Salvar / Carregar")]
    [SerializeField] private Button saveButton;
    [SerializeField] private Button loadButton;
    [SerializeField] private SaveMenuController saveMenu;

    [Header("Regressar ao Título")]
    [SerializeField] private Button returnToTitleButton;
    [Tooltip("Nome da cena de título (SceneManager.LoadSceneAsync).")]
    [SerializeField] private string titleSceneName;

    [Header("Sistema (Regressar ao Coração de Gaia)")]
    [Tooltip("Botão discreto, longe de 'Retomar', que abre o sub-menu Sistema.")]
    [SerializeField] private Button systemMenuButton;
    [SerializeField] private SystemMenuUI systemMenu;
    [Tooltip("Nome da cena do Coração de Gaia (SceneManager.LoadSceneAsync).")]
    [SerializeField] private string heartOfGaiaSceneName;

    [Header("Sons")]
    [SerializeField] private AudioClip toggleSfx;
    [SerializeField] private AudioClip confirmSfx;

    public string SectionName => "OPÇÕES";
    public GameObject Root => root != null ? root : gameObject;

    private bool initialized;

    private void Awake()
    {
        if (masterVolumeSlider != null) masterVolumeSlider.onValueChanged.AddListener(OnMasterVolumeChanged);
        if (musicVolumeSlider != null) musicVolumeSlider.onValueChanged.AddListener(OnMusicVolumeChanged);
        if (bgsVolumeSlider != null) bgsVolumeSlider.onValueChanged.AddListener(OnBgsVolumeChanged);
        if (sfxVolumeSlider != null) sfxVolumeSlider.onValueChanged.AddListener(OnSfxVolumeChanged);

        if (gaiaVoiceToggle != null) gaiaVoiceToggle.onValueChanged.AddListener(OnGaiaVoiceToggled);
        if (textSpeedSlider != null) textSpeedSlider.onValueChanged.AddListener(OnTextSpeedChanged);
        if (textSizeButton != null) textSizeButton.onClick.AddListener(OnTextSizeCycle);
        if (vibrationToggle != null) vibrationToggle.onValueChanged.AddListener(OnVibrationToggled);
        if (screenShakeToggle != null) screenShakeToggle.onValueChanged.AddListener(OnScreenShakeToggled);
        if (reducedFlashesToggle != null) reducedFlashesToggle.onValueChanged.AddListener(OnReducedFlashesToggled);

        if (apoloAuraToggle != null) apoloAuraToggle.onValueChanged.AddListener(OnApoloAuraToggled);
        if (gaiaAuraToggle != null)  gaiaAuraToggle.onValueChanged.AddListener(OnGaiaAuraToggled);
        if (zeusAuraToggle != null)  zeusAuraToggle.onValueChanged.AddListener(OnZeusAuraToggled);

        if (languageButton != null) languageButton.onClick.AddListener(OnLanguageCycle);

        if (changeControlsButton != null) changeControlsButton.onClick.AddListener(OpenRebindSection);
        if (rebindSection != null) rebindSection.Closed += OnSubPanelClosed;

        if (saveButton != null) saveButton.onClick.AddListener(() => saveMenu?.OpenForSave());
        if (loadButton != null) loadButton.onClick.AddListener(() => saveMenu?.OpenForLoad());

        if (returnToTitleButton != null) returnToTitleButton.onClick.AddListener(OnReturnToTitle);

        if (systemMenuButton != null) systemMenuButton.onClick.AddListener(OpenSystemMenu);
        if (systemMenu != null)
        {
            systemMenu.Closed += OnSubPanelClosed;
            systemMenu.ReturnToGaiaHeartConfirmed += OnReturnToGaiaHeartConfirmed;
        }

        if (rebindSection != null) rebindSection.Root.SetActive(false);
        if (systemMenu != null) systemMenu.Root.SetActive(false);
    }

    // ---------------- IPauseMenuSection ----------------

    public void Refresh()
    {
        var audio = AudioManager.Instance;
        var settings = GameSettings.Instance;

        if (masterVolumeSlider != null && audio != null) masterVolumeSlider.SetValueWithoutNotify(audio.MasterVolume);
        if (musicVolumeSlider != null && audio != null) musicVolumeSlider.SetValueWithoutNotify(audio.BgmVolume);
        if (bgsVolumeSlider != null && audio != null) bgsVolumeSlider.SetValueWithoutNotify(audio.BgsVolume);
        if (sfxVolumeSlider != null && audio != null) sfxVolumeSlider.SetValueWithoutNotify(audio.SeVolume);

        if (gaiaVoiceToggle != null && settings != null) gaiaVoiceToggle.SetIsOnWithoutNotify(settings.GaiaVoiceDubbed);
        RefreshGaiaVoiceText();

        if (textSpeedSlider != null && settings != null) textSpeedSlider.SetValueWithoutNotify(settings.TextSpeed);
        RefreshTextSizeText();

        if (vibrationToggle != null && settings != null) vibrationToggle.SetIsOnWithoutNotify(settings.VibrationEnabled);
        if (screenShakeToggle != null && settings != null) screenShakeToggle.SetIsOnWithoutNotify(settings.ScreenShakeEnabled);
        if (reducedFlashesToggle != null && settings != null) reducedFlashesToggle.SetIsOnWithoutNotify(settings.ReducedFlashes);

        RefreshLanguageText();
        RefreshAuraRows();

        ShowMainContent();
        initialized = true;

        SelectFirst();
    }

    public void OnHide()
    {
        if (rebindSection != null) rebindSection.Root.SetActive(false);
        if (systemMenu != null) systemMenu.Root.SetActive(false);
    }

    // ---------------- Volumes ----------------

    private void OnMasterVolumeChanged(float value) => AudioManager.Instance?.SetMasterVolume(value);
    private void OnMusicVolumeChanged(float value) => AudioManager.Instance?.SetBgmVolume(value);
    private void OnBgsVolumeChanged(float value) => AudioManager.Instance?.SetBgsVolume(value);
    private void OnSfxVolumeChanged(float value) => AudioManager.Instance?.SetSeVolume(value);

    // ---------------- Voz de Gaia ----------------

    private void OnGaiaVoiceToggled(bool value)
    {
        GameSettings.Instance?.SetGaiaVoiceDubbed(value);
        RefreshGaiaVoiceText();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void RefreshGaiaVoiceText()
    {
        if (gaiaVoiceValueText == null) return;
        bool dubbed = GameSettings.Instance != null && GameSettings.Instance.GaiaVoiceDubbed;
        gaiaVoiceValueText.text = dubbed ? gaiaVoiceOnText : gaiaVoiceOffText;
    }

    // ---------------- Texto ----------------

    private void OnTextSpeedChanged(float value) => GameSettings.Instance?.SetTextSpeed(value);

    private void OnTextSizeCycle()
    {
        GameSettings.Instance?.CycleTextSize();
        RefreshTextSizeText();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void RefreshTextSizeText()
    {
        if (textSizeValueText == null || GameSettings.Instance == null) return;

        textSizeValueText.text = GameSettings.Instance.CurrentTextSize switch
        {
            TextSize.Pequeno => textSizePequenoText,
            TextSize.Grande => textSizeGrandeText,
            _ => textSizeMedioText,
        };
    }

    // ---------------- Vibração ----------------

    private void OnVibrationToggled(bool value)
    {
        GameSettings.Instance?.SetVibrationEnabled(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    // ---------------- Acessibilidade ----------------

    private void OnScreenShakeToggled(bool value)
    {
        GameSettings.Instance?.SetScreenShakeEnabled(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void OnReducedFlashesToggled(bool value)
    {
        GameSettings.Instance?.SetReducedFlashes(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    // ---------------- Auras Pós-game ----------------

    private void RefreshAuraRows()
    {
        var vars = GameVariables.Instance;
        var settings = GameSettings.Instance;

        bool apoloObtained = apoloEmblemData != null
            && !string.IsNullOrEmpty(apoloEmblemData.obtainedVariable)
            && (vars?.GetBool(apoloEmblemData.obtainedVariable) ?? false);
        bool gaiaObtained = gaiaEmblemData != null
            && !string.IsNullOrEmpty(gaiaEmblemData.obtainedVariable)
            && (vars?.GetBool(gaiaEmblemData.obtainedVariable) ?? false);
        bool zeusObtained = zeusEmblemData != null
            && !string.IsNullOrEmpty(zeusEmblemData.obtainedVariable)
            && (vars?.GetBool(zeusEmblemData.obtainedVariable) ?? false);

        // Rows só visíveis se o emblema foi obtido.
        if (apoloAuraRow != null) apoloAuraRow.SetActive(apoloObtained);
        if (gaiaAuraRow  != null) gaiaAuraRow.SetActive(gaiaObtained);
        if (zeusAuraRow  != null) zeusAuraRow.SetActive(zeusObtained);

        // Reflecte o valor actual da preferência.
        if (apoloAuraToggle != null && settings != null) apoloAuraToggle.SetIsOnWithoutNotify(settings.ApoloAuraEnabled);
        if (gaiaAuraToggle  != null && settings != null) gaiaAuraToggle.SetIsOnWithoutNotify(settings.GaiaAuraEnabled);
        if (zeusAuraToggle  != null && settings != null) zeusAuraToggle.SetIsOnWithoutNotify(settings.ZeusAuraEnabled);
    }

    private void OnApoloAuraToggled(bool value)
    {
        GameSettings.Instance?.SetApoloAuraEnabled(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void OnGaiaAuraToggled(bool value)
    {
        GameSettings.Instance?.SetGaiaAuraEnabled(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void OnZeusAuraToggled(bool value)
    {
        GameSettings.Instance?.SetZeusAuraEnabled(value);
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    // ---------------- Idioma ----------------

    private void OnLanguageCycle()
    {
        GameSettings.Instance?.CycleLanguage();
        RefreshLanguageText();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void RefreshLanguageText()
    {
        if (languageValueText == null) return;
        var lang = GameSettings.Instance != null ? GameSettings.Instance.Language : GameLanguage.Portugues;
        languageValueText.text = GameSettings.LanguageDisplayName(lang);
    }

    // ---------------- Mudar Controles / Sistema (sub-painéis) ----------------

    private void OpenRebindSection()
    {
        if (rebindSection == null) return;

        HideMainContent();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
        rebindSection.Open();
    }

    private void OpenSystemMenu()
    {
        if (systemMenu == null) return;

        HideMainContent();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
        systemMenu.Open();
    }

    private void OnSubPanelClosed()
    {
        ShowMainContent();
        SelectFirst();
        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    private void HideMainContent()
    {
        if (mainContentRoot != null) mainContentRoot.SetActive(false);
    }

    private void ShowMainContent()
    {
        if (mainContentRoot != null) mainContentRoot.SetActive(true);
    }

    private void SelectFirst()
    {
        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }

    // ---------------- Regressar ao Título / Coração de Gaia ----------------

    private void OnReturnToTitle() => GoToScene(titleSceneName);

    private void OnReturnToGaiaHeartConfirmed()
    {
        PauseMenuController.Instance?.PlaySfx(confirmSfx);
        GoToScene(heartOfGaiaSceneName);
    }

    private void GoToScene(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
        {
            Debug.LogWarning("[OptionsSectionUI] Nome de cena vazio — não é possível mudar de cena.");
            return;
        }

        PauseMenuController.Instance?.Close();
        GamePauseUtil.Resume();

        // Tarefa #16 (tela de loading): troca de cena via LoadingScreenController
        // (overlay com fade), em vez de SceneManager directo.
        LoadingScreenController.Instance.LoadScene(sceneName);
    }
}

/// <summary>
/// Sub-menu "Sistema" da secção Opções — contém apenas "Regressar ao Coração
/// de Gaia", propositadamente isolado do resto de Opções (GDD: "Não deve ficar
/// perto de 'Retomar', porque poderia ser escolhido acidentalmente").
///
/// Mostra o aviso completo ("Regressar ao Coração de Gaia? O progresso
/// recente não gravado será perdido. A tua posição nesta área será perdida.")
/// e exige <see cref="HoldToConfirmButton"/> (segurar ~1s) para confirmar.
/// Fecha com "Voltar" (UI) ou "B"/Escape (ICancelHandler) sem confirmar.
/// </summary>
public class SystemMenuUI : MonoBehaviour, ICancelHandler
{
    [SerializeField] private GameObject root;

    [SerializeField] private TMP_Text warningText;
    [SerializeField] private string warningMessage =
        "Regressar ao Coração de Gaia? O progresso recente não gravado será perdido. A tua posição nesta área será perdida.";

    [SerializeField] private HoldToConfirmButton returnToGaiaHeartButton;
    [SerializeField] private Button backButton;

    [Tooltip("Primeiro elemento a seleccionar ao abrir este sub-menu.")]
    [SerializeField] private Selectable firstSelectable;

    public GameObject Root => root != null ? root : gameObject;

    /// <summary>Disparado quando este sub-menu fecha (botão "Voltar" ou Cancel) — OptionsSectionUI usa isto para devolver a selecção à página principal.</summary>
    public event System.Action Closed;

    /// <summary>Disparado quando o jogador confirma "Regressar ao Coração de Gaia" (hold completo).</summary>
    public event System.Action ReturnToGaiaHeartConfirmed;

    private void Awake()
    {
        if (warningText != null) warningText.text = warningMessage;
        if (backButton != null) backButton.onClick.AddListener(Close);
        if (returnToGaiaHeartButton != null) returnToGaiaHeartButton.OnConfirmed.AddListener(OnConfirmed);

        if (root != null) root.SetActive(false);
    }

    public void Open()
    {
        if (root != null) root.SetActive(true);

        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }

    public void Close()
    {
        if (root != null) root.SetActive(false);
        Closed?.Invoke();
    }

    /// <summary>Chamado automaticamente pelo Input System UI Module quando "Cancel" (B/Escape) dispara com este painel seleccionado.</summary>
    public void OnCancel(BaseEventData eventData) => Close();

    private void OnConfirmed() => ReturnToGaiaHeartConfirmed?.Invoke();
}
